from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.route('/api/<path:subpath>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def api_gateway(subpath):
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return jsonify({'error': 'Authorization header missing'}), 401

    token = auth_header.split(" ")[1]
    try:
        # For development: verify=False to speed up. In production, set verify=True with proper key.
        decoded_token = jwt.decode(token, options={"verify_signature": False})
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

    # Extract user claims
    user_claims = decoded_token.get('claims', {})

    # Forward to the backend service
    # Implement your backend forwarding logic here
    # For illustration we return the user claims and requested path
    return jsonify({
        'user_claims': user_claims,
        'subpath': subpath,
        'message': 'Forwarding request to backend service'
    })

if __name__ == '__main__':
    app.run(debug=True)